public List grayCode(int n) {
    List result = new ArrayList<>();
    result.add(0);

    for (int i = 0; i < n; i++) {
        int size = result.size();
        for (int j = size - 1; j >= 0; j--) {
            result.add(result.get(j) | (1 << i));
        }
    }

    return result;
}

